'use client';

import { useState, type ReactNode, type MouseEvent } from 'react';
import { motion } from 'framer-motion';

/* ─── BentoCard with mouse-follow glow ──────────────────────── */
function BentoCard({
    children,
    className = '',
    span = '',
}: {
    children: ReactNode;
    className?: string;
    span?: string;
}) {
    const handleMouseMove = (e: MouseEvent<HTMLDivElement>) => {
        const rect = e.currentTarget.getBoundingClientRect();
        e.currentTarget.style.setProperty('--x', `${e.clientX - rect.left}px`);
        e.currentTarget.style.setProperty('--y', `${e.clientY - rect.top}px`);
    };

    return (
        <motion.div
            initial={{ opacity: 0, y: 24 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true, margin: '-60px' }}
            transition={{ type: 'spring', stiffness: 120, damping: 20 }}
            onMouseMove={handleMouseMove}
            className={`bento-glow group relative overflow-hidden rounded-2xl border border-white/[0.06] bg-white/[0.02] backdrop-blur-sm ${span} ${className}`}
        >
            <div className="relative z-10 h-full p-5 md:p-6">{children}</div>
        </motion.div>
    );
}

