/* ─── Box 4: Interactive Toggles ────────────────────────────── */
function ToggleBox() {
    const [switches, setSwitches] = useState([true, false, true]);
    const labels = ['Dark Mode', 'Animations', 'Type Safety'];

    return (
        <div>
            <h3 className="mb-1 text-sm font-semibold text-white/70">Interactive</h3>
            <p className="mb-4 text-xs text-white/30">Try it yourself</p>
            <div className="space-y-3">
                {labels.map((label, i) => (
                    <label key={label} className="flex cursor-pointer items-center justify-between">
                        <span className="text-xs text-white/50">{label}</span>
                        <button
                            type="button"
                            role="switch"
                            aria-checked={switches[i]}
                            onClick={() => {
                                const next = [...switches];
                                next[i] = !next[i];
                                setSwitches(next);
                            }}
                            className={`relative inline-flex h-5 w-9 shrink-0 rounded-full transition-colors duration-200 ${switches[i] ? 'bg-blue-500' : 'bg-white/10'}`}
                        >
                            <span className={`inline-block h-4 w-4 rounded-full shadow-sm transition-transform duration-200 mt-0.5 ${switches[i] ? 'translate-x-[18px] bg-white' : 'translate-x-0.5 bg-white'}`} />
                        </button>
                    </label>
                ))}
            </div>
        </div>
    );
}

